import { ParsedFilenameResult } from '../types';
import { DocState } from '../types';

/**
 * Parsea y valida el nombre de archivo según la norma institucional estricta.
 * Formato esperado: PROYECTO - Microproceso - TIPO - Versión
 * Ejemplo: HPC - Gestión de Proyectos - ASIS - v1.0
 */
export const parseDocumentFilename = (
  fullFilename: string, 
  expectedProject?: string,
  expectedMicro?: string,
  expectedType?: string,
  expectedRequestType?: 'INITIATED' | 'IN_PROCESS' | 'INTERNAL' | 'REFERENT' | 'CONTROL'
): ParsedFilenameResult => {
  const result: ParsedFilenameResult = {
    valido: false,
    errores: []
  };

  // 1. Separar nombre de extensión
  const lastDotIndex = fullFilename.lastIndexOf('.');
  const filenameBase = lastDotIndex !== -1 ? fullFilename.substring(0, lastDotIndex) : fullFilename;

  // 2. Validar longitud máxima (80 caracteres)
  if (filenameBase.length > 80) {
    result.errores.push(`El nombre del archivo excede 80 caracteres.`);
  }

  // 3. Validar Estructura General
  const parts = filenameBase.split(' - ');

  if (parts.length < 4) {
    result.errores.push('Formato incorrecto. Use: "PROYECTO - Microproceso - TIPO - Versión".');
    return result;
  }

  const proyecto = parts[0];
  const version = parts[parts.length - 1];
  const tipoCodigo = parts[parts.length - 2];
  const microproceso = parts.slice(1, parts.length - 2).join(' - ');

  // 4. Validar Proyecto
  if (proyecto !== 'HPC' && proyecto !== 'HSR') {
    result.errores.push(`Proyecto inválido: ${proyecto}.`);
  } else if (expectedProject && proyecto !== expectedProject) {
    result.errores.push(`Proyecto no coincide con la solicitud.`);
  }
  result.proyecto = proyecto as 'HPC' | 'HSR';

  // 5. Validar Microproceso
  if (!microproceso || microproceso.trim() === '') {
    result.errores.push('Microproceso vacío.');
  } else if (expectedMicro && microproceso !== expectedMicro) {
    result.errores.push(`Microproceso no coincide.`);
  }
  result.microproceso = microproceso;

  // 6. Validar Tipo
  const mapTypeToCode: Record<string, string> = {
      'AS IS': 'ASIS', 'TO BE': 'TOBE', 'FCE': 'FCE', 'PM': 'PM'
  };
  const validCodes = Object.values(mapTypeToCode);
  if (!validCodes.includes(tipoCodigo)) {
      result.errores.push(`Tipo inválido: ${tipoCodigo}.`);
  }
  if (expectedType) {
      const expectedCode = mapTypeToCode[expectedType];
      if (tipoCodigo !== expectedCode) {
          result.errores.push(`Tipo no coincide con la solicitud.`);
      }
  }
  result.tipo = tipoCodigo;

  // 7. Analizar Versión y Reglas de Solicitud
  result.nomenclatura = version;

  // Regex básicos
  const regexInitiated = /^0\.0$/;              // 0.0 (Estricto)
  const regexInProcess = /^0\.(\d+)$/;          // 0.n (Sin 'v', n > 0)
  const regexInternal = /^v0\.(\d+)$/;          // v0.n (Con 'v', impar)
  const regexReferent = /^v1\.(\d+)\.(\d+)$/;   // v1.n.i
  const regexControl = /^v1\.(\d+)\.(\d+)AR$/;  // v1.n.iAR
  const regexStandard = /^v?\d+(\.\d+)*([A-Z]+)?$/;

  if (expectedRequestType) {
      if (expectedRequestType === 'INITIATED') {
          if (!regexInitiated.test(version)) {
              result.errores.push('Para estado "Iniciado" la versión debe ser estrictamente "0.0".');
          }
      } else if (expectedRequestType === 'IN_PROCESS') {
          const match = version.match(regexInProcess);
          if (!match) {
              result.errores.push('Para "En Proceso" el formato debe ser "0.n" (ej: 0.1, 0.2) sin la letra "v".');
          } else {
               const n = parseInt(match[1]);
               if (n === 0) {
                   result.errores.push('La versión 0.0 corresponde a "Iniciado". Para "En Proceso" n debe ser mayor a 0 (ej: 0.1).');
               }
          }
      } else if (expectedRequestType === 'INTERNAL') {
          const match = version.match(regexInternal);
          if (!match) {
              result.errores.push('Para Revisión Interna el formato debe ser "v0.n" (con v).');
          } else {
              const n = parseInt(match[1]);
              if (n % 2 === 0) {
                  result.errores.push(`Para Revisión Interna el dígito "n" (${n}) debe ser IMPAR (ej: v0.1, v0.3).`);
              }
          }
      } else if (expectedRequestType === 'REFERENT') {
          const match = version.match(regexReferent);
          if (!match) {
              result.errores.push('Para Revisión Interna Referente el formato debe ser "v1.n.i" (ej: v1.0.1).');
          } else {
              const i = parseInt(match[2]);
              if (i % 2 === 0) {
                  result.errores.push(`Para Revisión Interna Referente el dígito "i" (${i}) debe ser IMPAR (ej: v1.0.1, v1.0.3).`);
              }
          }
      } else if (expectedRequestType === 'CONTROL') {
          const match = version.match(regexControl);
          if (!match) {
              result.errores.push('Para Revisión Interna Control el formato debe ser "v1.n.iAR" (ej: v1.0.1AR).');
          } else {
              const i = parseInt(match[2]);
              if (i % 2 === 0) {
                  result.errores.push(`Para Revisión Interna Control el dígito "i" (${i}) debe ser IMPAR (ej: v1.0.1AR).`);
              }
          }
      }
  } else {
      // Validación genérica si no hay tipo de solicitud explícito
      if (!regexStandard.test(version)) {
          // Intentamos ser permisivos con 0.0 y 0.n si no hay expectedType pero validamos formato general
          if (!regexInitiated.test(version) && !regexInProcess.test(version)) {
             result.errores.push(`Formato de versión inválido: ${version}`);
          }
      }
  }

  // Logic map for state detection (Auto-detect if not enforced)
  // IMPROVED LOGIC FOR INTERMEDIATE STATES
  if (result.errores.length === 0) {
      if (version.endsWith('ACG')) {
          result.estado = 'Aprobado';
          result.porcentaje = 100;
      } else if (version.endsWith('AR')) {
          // v1.nAR vs v1.n.iAR
          if (version.match(/^v1\.(\d+)\.(\d+)AR$/)) {
              result.estado = 'Revisión Interna Control'; // Intermediate
              result.porcentaje = 90;
          } else {
              result.estado = 'Enviado a Control de Gestión'; // v1.nAR
              result.porcentaje = 90;
          }
      } else if (version.startsWith('v1.')) {
          // v1.n vs v1.n.i
          if (version.split('.').length > 2) {
              result.estado = 'Revisión Interna Referente'; // v1.n.i
              result.porcentaje = 80;
          } else {
              result.estado = 'Enviado a Referente'; // v1.n
              result.porcentaje = 80;
          }
      } else if (version.startsWith('v0.')) {
          result.estado = 'En revisión interna'; 
          result.porcentaje = 60;
      } else if (version === '0.0') {
          result.estado = 'Iniciado';
          result.porcentaje = 10;
      } else if (/^0\.\d+$/.test(version)) {
          result.estado = 'En Proceso';
          result.porcentaje = 30;
      } else {
          result.estado = 'En Proceso'; 
          result.porcentaje = 30;
      }
  }

  result.valido = result.errores.length === 0;
  return result;
};

/**
 * Valida las reglas de transición de versiones para el COORDINADOR (Aprobar/Rechazar).
 */
export const validateCoordinatorRules = (
    filename: string,
    currentVersion: string, 
    currentState: DocState,
    action: 'APPROVE' | 'REJECT'
): { valid: boolean; error?: string; hint?: string } => {

    // Parse parts
    const parts = filename.replace(/\.[^/.]+$/, "").split(' - ');
    if (parts.length < 4) return { valid: false, error: 'Formato de nombre inválido.' };
    const newVersion = parts[parts.length - 1];

    // Helper to decompose version into components
    const getParts = (v: string) => {
        let m;
        // v0.n (Internal Request or Reject Internal)
        m = v.match(/^v?0\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: false, type: 'v0.n' };

        // v1.n (Internal Approve or Referent Approve)
        m = v.match(/^v1\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: false, type: 'v1.n' };

        // v1.n.i (Referent Request OR Referent Reject)
        m = v.match(/^v1\.(\d+)\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: parseInt(m[2]), ar: false, acg: false, type: 'v1.n.i' };

        // v1.n.iAR (Control Request OR Control Reject)
        m = v.match(/^v1\.(\d+)\.(\d+)AR$/);
        if (m) return { n: parseInt(m[1]), i: parseInt(m[2]), ar: true, acg: false, type: 'v1.n.iAR' };

        // v1.nAR (Control Approve / Version Advance)
        m = v.match(/^v1\.(\d+)AR$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: true, acg: false, type: 'v1.nAR' };

        // v1.nACG (Final Approval)
        m = v.match(/^v1\.(\d+)ACG$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: true, type: 'v1.nACG' };

        return null;
    };

    const current = getParts(currentVersion);
    const incoming = getParts(newVersion);

    if (!incoming) return { valid: false, error: 'Formato de versión no reconocido.' };

    // =========================================================
    // ETAPA 1: REVISIÓN INTERNA (v0.x)
    // =========================================================
    if (currentState === DocState.INTERNAL_REVIEW) {
        if (action === 'APPROVE') {
            // Aprobar revisión interna: subir v1.n (entero)
            if (incoming.type !== 'v1.n') return { valid: false, error: 'Aprobación requiere v1.n (Ej: v1.0).' };
            return { valid: true };
        } else {
            // Rechazar revisión interna: subir v0.n (par)
            if (incoming.type !== 'v0.n') return { valid: false, error: 'Rechazo requiere v0.n.' };
            if (incoming.n % 2 !== 0) return { valid: false, error: `Para rechazar, "n" (${incoming.n}) debe ser PAR (ej: v0.2, v0.4).` };
            return { valid: true };
        }
    }

    // =========================================================
    // ETAPA 2: REFERENTE / v1.x (Lógica Avanzada Solicitada)
    // =========================================================
    if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) {
        if (action === 'APPROVE') {
            // Se permiten dos caminos para aprobar:
            // 1. Consolidación: v1.n (Sin AR) -> Para enviar a referente.
            // 2. Control: v1.nAR (Con AR) -> Para enviar a Control de Gestión.

            if (incoming.type === 'v1.n') {
                // CAMINO 1: Consolidación (v1.0.1 -> v1.1)
                // Regla: n debe ser mayor al actual.
                if (current && incoming.n <= current.n) return { valid: false, error: `Para consolidar versión, v1.${incoming.n} debe ser mayor a la actual (v1.${current.n}...).` };
                return { valid: true };

            } else if (incoming.type === 'v1.nAR') {
                // CAMINO 2: Enviar a Control (AR)

                // Caso A: Vengo de borrador (v1.n.i -> v1.(n+1)AR)
                if (current?.type === 'v1.n.i') {
                    if (incoming.n <= current.n) return { valid: false, error: `Al aprobar borrador para Control, debe consolidar versión (v1.${current.n + 1}AR).` };
                    return { valid: true };
                }

                // Caso B: Vengo de versión limpia (v1.n -> v1.nAR)
                if (current?.type === 'v1.n') {
                    if (incoming.n !== current.n) return { valid: false, error: `Al aprobar versión limpia para Control, mantenga el número (v1.${current.n}AR).` };
                    return { valid: true };
                }

                // Fallback por si el estado actual no coincide con lo esperado
                if (current && incoming.n < current.n) return { valid: false, error: 'No puede bajar de versión.' };
                return { valid: true };

            } else {
                return { valid: false, error: 'Aprobación requiere v1.n (Consolidar) o v1.nAR (Control).' };
            }

        } else {
            // RECHAZAR: v1.n.i (Par y mayor)
            if (incoming.type !== 'v1.n.i') return { valid: false, error: 'Rechazo requiere v1.n.i (Ej: v1.0.2).' };
            if (incoming.i! % 2 !== 0) return { valid: false, error: `Para rechazar, el último dígito "i" (${incoming.i}) debe ser PAR.` };

            // Validar que no baje versión 'n'
            if (current && incoming.n !== current.n) return { valid: false, error: `El rechazo debe mantener la versión base v1.${current.n}.` };
            // Validar que 'i' sea mayor (si venimos de borrador)
            if (current?.i !== null && incoming.i! <= current!.i!) return { valid: false, error: `El dígito "i" (${incoming.i}) debe ser mayor al actual.` };

            return { valid: true };
        }
    }

    // =========================================================
    // ETAPA 3: CONTROL DE GESTIÓN (v1.xAR)
    // =========================================================
    if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) {
        if (action === 'APPROVE') {
            // Aprobar cambios de versión o final
            if (incoming.type === 'v1.nAR') {
                if (current && incoming.n <= current.n) return { valid: false, error: `Para avanzar versión, v1.${incoming.n}AR debe ser mayor a la actual (v1.${current.n}...).` };
                return { valid: true };
            }
            if (incoming.type === 'v1.nACG') {
                return { valid: true };
            }
            return { valid: false, error: 'Aprobación requiere v1.nAR (avance) o v1.nACG (final).' };
        } else {
            // Rechazar Control: subir v1.n.iAR (i par y mayor al anterior)
            if (incoming.type !== 'v1.n.iAR') return { valid: false, error: 'Rechazo requiere v1.n.iAR (Ej: v1.0.2AR).' };
            if (incoming.i! % 2 !== 0) return { valid: false, error: `Para rechazar, el dígito "i" (${incoming.i}) debe ser PAR.` };

            if (current && current.type === 'v1.n.iAR') {
                 if (incoming.i! <= current.i!) return { valid: false, error: `El dígito "i" (${incoming.i}) debe ser mayor al actual (${current.i}).` };
            }
            return { valid: true };
        }
    }

    // Fallback for other states (not strict)
    return { valid: true };
}

/**
 * Genera el texto de ayuda para el modal
 */
export const getCoordinatorRuleHint = (currentState: DocState, action: 'APPROVE' | 'REJECT'): string => {
    if (action === 'REJECT') {
        if (currentState === DocState.INTERNAL_REVIEW) return 'Formato: v0.n (n PAR). Ej: v0.2';
        if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) return 'Formato: v1.n.i (i PAR). Ej: v1.0.2';
        if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) return 'Formato: v1.n.iAR (i PAR y mayor). Ej: v1.0.2AR';
    } else {
        if (currentState === DocState.INTERNAL_REVIEW) return 'Formato: v1.n (Ej: v1.0)';

        if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) {
            return 'Opción 1: v1.n (Consolidar) / Opción 2: v1.nAR (Enviar a Control)';
        }

        if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) return 'Opción 1: v1.nAR (Avance) / Opción 2: v1.nACG (Final)';
    }
    return 'Formato estándar';
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { User, DocState, DocType, UserHierarchy, UserRole, Document, FullHierarchy } from '../types';
import { parseDocumentFilename } from '../utils/filenameParser';
import { Save, ArrowLeft, Upload, FileCheck, FileX, AlertTriangle, Info, Layers, FileType, FilePlus, ListFilter, Lock, RefreshCw } from 'lucide-react';

interface Props {
  user: User;
}

// Request Types mapped to Parser Logic
type RequestType = 'INITIATED' | 'IN_PROCESS' | 'INTERNAL' | 'REFERENT' | 'CONTROL';

// Map States to Levels for filtering
const STATE_LEVELS: Record<DocState, number> = {
    [DocState.NOT_STARTED]: 0,
    [DocState.INITIATED]: 1,
    [DocState.IN_PROCESS]: 2,
    [DocState.INTERNAL_REVIEW]: 3,
    [DocState.SENT_TO_REFERENT]: 4,
    [DocState.REFERENT_REVIEW]: 4,
    [DocState.SENT_TO_CONTROL]: 5,
    [DocState.CONTROL_REVIEW]: 5,
    [DocState.APPROVED]: 6,
    [DocState.REJECTED]: 0 // Special case
};

const REQUEST_TYPE_LEVELS: Record<RequestType, number> = {
    'INITIATED': 1,
    'IN_PROCESS': 2,
    'INTERNAL': 3,
    'REFERENT': 4,
    'CONTROL': 5
};

const CreateDocument: React.FC<Props> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); // Hook to access passed state
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);

  // Hierarchy Selection State with Strict Typing
  const [userHierarchy, setUserHierarchy] = useState<UserHierarchy>({});
  const [fullHierarchyCache, setFullHierarchyCache] = useState<FullHierarchy>({}); // Cache full hierarchy for assignments

  // Matrix Requirement Map (Project|Micro -> AllowedTypes[])
  const [requirementsMap, setRequirementsMap] = useState<Record<string, DocType[]>>({});

  const [selectedProject, setSelectedProject] = useState<string>('');
  const [selectedMacro, setSelectedMacro] = useState<string>('');
  const [selectedProcess, setSelectedProcess] = useState<string>('');
  const [selectedMicro, setSelectedMicro] = useState<string>('');
  const [selectedDocType, setSelectedDocType] = useState<DocType | ''>('');

  // New: Request Type for Safety
  const [requestType, setRequestType] = useState<RequestType | ''>('');

  // Existing Document State (for filtering)
  const [existingDoc, setExistingDoc] = useState<Document | null>(null);
  const [existingDocLevel, setExistingDocLevel] = useState<number>(0);

  // File Upload State
  const [file, setFile] = useState<File | undefined>(undefined);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Inferred Workflow State
  const [detectedState, setDetectedState] = useState<DocState>(DocState.INITIATED);
  const [detectedVersion, setDetectedVersion] = useState('0.0');
  const [detectedProgress, setDetectedProgress] = useState(10);

  // Cache of all docs for quick lookup
  const [allDocsCache, setAllDocsCache] = useState<Document[]>([]);

  useEffect(() => {
      loadData();
  }, []);

  // Effect to find existing document when selection changes
  useEffect(() => {
      if (selectedProject && selectedMicro && selectedDocType) {
          const found = allDocsCache.find(d => 
              d.project === selectedProject && 
              (d.microprocess === selectedMicro || d.title.includes(selectedMicro)) &&
              d.docType === selectedDocType
          );

          if (found) {
              setExistingDoc(found);
              // Calculate effective level (Use MAX logic if multiple found, but find returns first. Assuming cache is sorted by update)
              const level = STATE_LEVELS[found.state] || 0;
              setExistingDocLevel(level);
          } else {
              setExistingDoc(null);
              setExistingDocLevel(0);
          }
      } else {
          setExistingDoc(null);
          setExistingDocLevel(0);
      }

      // Reset request type when hierarchy changes to prevent invalid states
      setRequestType('');
      resetFile();

  }, [selectedProject, selectedMicro, selectedDocType, allDocsCache]);

  const loadData = async () => {
      // 1. Cargar Mapa de Requisitos, Jerarquía y Documentos Existentes
      try {
          // Always load full hierarchy to get assignment data
          const [reqMap, full, docs] = await Promise.all([
              HierarchyService.getRequiredTypesMap(),
              HierarchyService.getFullHierarchy(),
              DocumentService.getAll()
          ]);

          setRequirementsMap(reqMap);
          setAllDocsCache(docs);
          setFullHierarchyCache(full);

          // Build View Hierarchy based on Role
          if (user.role === UserRole.ADMIN) {
               const adminTree: UserHierarchy = {};
               // Convertir FullHierarchy (nodos complejos) a UserHierarchy (solo nombres)
               Object.keys(full).forEach(p => {
                   adminTree[p] = {};
                   Object.keys(full[p]).forEach(m => {
                       adminTree[p][m] = {};
                       Object.keys(full[p][m]).forEach(proc => {
                           adminTree[p][m][proc] = full[p][m][proc].map(n => n.name);
                       });
                   });
               });
               setUserHierarchy(adminTree);
          } else {
              // Si es Analista/Coordinador, cargamos SU jerarquía filtrada
              const userH = await HierarchyService.getUserHierarchy(user.id);
              setUserHierarchy(userH);
          }

          // 2. PRE-FILL LOGIC (Si viene desde Dashboard o Detalle)
          if (location.state?.prefill) {
              const { project, macro, process, micro, docType } = location.state.prefill;
              if (project) setSelectedProject(project);
              if (macro) setSelectedMacro(macro);
              if (process) setSelectedProcess(process);
              if (micro) setSelectedMicro(micro);

              // Validate if the pre-filled docType is actually allowed
              if (docType && project && micro) {
                  // FIX: Use normalized key for lookup here too
                  const key = `${normalizeHeader(project)}|${normalizeHeader(micro)}`;
                  const allowed = reqMap[key] || [];
                  if (allowed.includes(docType)) {
                      setSelectedDocType(docType);
                  }
              }
          }
      } catch (e) {
          console.error("Error loading create document data", e);
      } finally {
          setInitializing(false);
      }
  };

  // Helper functions for safe extraction of hierarchy arrays
  const getProjects = (): string[] => {
      return Object.keys(userHierarchy);
  };

  const getMacros = (): string[] => {
      if (!selectedProject || !userHierarchy[selectedProject]) return [];
      return Object.keys(userHierarchy[selectedProject]);
  };

  const getProcesses = (): string[] => {
      if (!selectedProject || !selectedMacro || !userHierarchy[selectedProject]?.[selectedMacro]) return [];
      return Object.keys(userHierarchy[selectedProject][selectedMacro]);
  };

  const getMicros = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess) return [];
      const processes = userHierarchy[selectedProject]?.[selectedMacro];
      if (!processes) return [];
      return processes[selectedProcess] || [];
  };

  // Helper to check allowed types based on Matrix
  const getAllowedDocTypes = (): DocType[] => {
      if (!selectedProject || !selectedMicro) return [];
      // FIX: Use normalizeHeader to match the key format stored in requirementsMap (created in backend service)
      const key = `${normalizeHeader(selectedProject)}|${normalizeHeader(selectedMicro)}`;
      return requirementsMap[key] || [];
  };

  // Find assignments from Full Hierarchy Cache
  const getAssigneesForSelection = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess || !selectedMicro) return [];
      const nodes = fullHierarchyCache[selectedProject]?.[selectedMacro]?.[selectedProcess] || [];
      const node = nodes.find(n => n.name === selectedMicro);
      return node?.assignees || [];
  };

  // Reset downstream selections when upstream changes
  const handleProjectChange = (val: string) => {
      setSelectedProject(val);
      setSelectedMacro('');
      setSelectedProcess('');
      setSelectedMicro('');
      resetFile();
  };

  const handleMacroChange = (val: string) => {
      setSelectedMacro(val);
      setSelectedProcess('');
      setSelectedMicro('');
      resetFile();
  };

  const handleProcessChange = (val: string) => {
      setSelectedProcess(val);
      setSelectedMicro('');
      resetFile();
  };

  const handleMicroChange = (val: string) => {
      setSelectedMicro(val);
      setSelectedDocType(''); // Reset type because allowed types change per micro
      resetFile();
  }

  const handleTypeChange = (val: string) => {
      setSelectedDocType(val as DocType);
      resetFile();
  }

  const handleRequestTypeChange = (val: string) => {
      setRequestType(val as RequestType);
      resetFile();
  }

  const resetFile = () => {
      setFile(undefined);
      setFileError([]);
      setIsFileValid(false);
      setTitle('');
      setDescription('');
      if (fileInputRef.current) {
          fileInputRef.current.value = '';
      }
  };

  const mapParserStateToEnum = (parserState: string): DocState => {
      switch (parserState) {
          case 'Iniciado': return DocState.INITIATED;
          case 'En Proceso': return DocState.IN_PROCESS;
          case 'En revisión interna': return DocState.INTERNAL_REVIEW;

          case 'Enviado a Referente': return DocState.SENT_TO_REFERENT;
          case 'Revisión Interna Referente': return DocState.REFERENT_REVIEW; // Updated mapping

          case 'Enviado a Control de Gestión': return DocState.SENT_TO_CONTROL;
          case 'Revisión Interna Control': return DocState.CONTROL_REVIEW; // Updated mapping

          case 'Aprobado': return DocState.APPROVED;
          default: return DocState.INITIATED;
      }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const selectedFile = e.target.files[0];
          setFile(selectedFile);

          // Validate logic with Strict Request Type
          const result = parseDocumentFilename(
              selectedFile.name,
              selectedProject,
              selectedMicro,
              selectedDocType || undefined,
              requestType || undefined // Pass the strict expected type
          );

          if (result.valido) {
              setIsFileValid(true);
              setFileError([]);

              const cleanMicro = result.microproceso || selectedMicro;
              const cleanType = result.tipo || selectedDocType;
              setTitle(`${cleanMicro} - ${cleanType}`);
              setDescription(`Carga de documento: ${cleanType} (${result.nomenclatura})`);

              if (result.estado) setDetectedState(mapParserStateToEnum(result.estado));
              if (result.nomenclatura) setDetectedVersion(result.nomenclatura);
              if (result.porcentaje) setDetectedProgress(result.porcentaje);

          } else {
              setIsFileValid(false);
              setFileError(result.errores);
              setTitle('');
              setDescription('');
          }
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !description || !file || !isFileValid || !selectedMicro || !selectedDocType || !requestType) return;

    setLoading(true);

    try {
      // Find assigned users from hierarchy to ensure correct assignment
      const matrixAssignees = getAssigneesForSelection();

      const newDoc = await DocumentService.create(
          title, 
          description, 
          user,
          detectedState,
          detectedVersion,
          detectedProgress,
          file,
          {
              project: selectedProject,
              macro: selectedMacro,
              process: selectedProcess,
              micro: selectedMicro,
              docType: selectedDocType,
              assignees: matrixAssignees // Pass matrix assignees
          }
      );

      navigate(`/doc/${newDoc.id}`);
    } catch (error: any) {
      console.error(error);
      alert('Error al crear documento: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  // Options filtering Logic
  const shouldShowOption = (type: RequestType): boolean => {
      if (!existingDoc || existingDoc.state === DocState.REJECTED) return true; // If rejected or new, allow all (typically reset)

      const optionLevel = REQUEST_TYPE_LEVELS[type];

      // LOGIC: Show only levels >= current level
      // Exception: If current is Internal Review (3), we allow Internal Review (3) [update] and Referent (4) [advance].
      return optionLevel >= existingDocLevel;
  };

  if (initializing) return <div className="p-8 text-center text-slate-500">Cargando permisos...</div>;

  const projects = getProjects() as string[];
  const macros = getMacros() as string[];
  const processes = getProcesses() as string[];
  const micros = getMicros() as string[];
  const docTypes = ['AS IS', 'FCE', 'PM', 'TO BE'];

  const allowedDocTypes = getAllowedDocTypes();

  return (
    <div className="max-w-4xl mx-auto pb-12">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 mb-6 text-sm">
            <ArrowLeft size={16} className="mr-1" />
            Volver
        </button>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
            <div className="mb-8 border-b border-slate-100 pb-4">
                <h1 className="text-2xl font-bold text-slate-900 mb-2">Nueva Solicitud</h1>
                <p className="text-slate-500">
                   Carga de documento para gestión y aprobación.
                </p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">

                {/* Step 1: Hierarchy Selection */}
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
                    <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                        <Layers size={18} className="text-indigo-600" />
                        1. Definición del Proceso
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {/* Project */}
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proyecto</label>
                            <select 
                                value={selectedProject}
